#include "spiffs_storage.h"
#include <SPIFFS.h>
void spiffs_setup(){if(!SPIFFS.begin(true)){Serial.println("[spiffs] Fail!");return;}Serial.printf("[spiffs] OK %luKB free\n",(unsigned long)(SPIFFS.totalBytes()-SPIFFS.usedBytes())/1024);}
bool spiffs_write(const char*p,const char*d){File f=SPIFFS.open(p,"w");if(!f)return false;f.print(d);f.close();return true;}
String spiffs_read(const char*p){File f=SPIFFS.open(p,"r");if(!f)return"";String s=f.readString();f.close();return s;}
bool spiffs_exists(const char*p){return SPIFFS.exists(p);}
void spiffs_remove(const char*p){SPIFFS.remove(p);}
uint32_t spiffs_free_bytes(){return SPIFFS.totalBytes()-SPIFFS.usedBytes();}
